"use client"

import React, { useCallback, useEffect, useState } from "react"
import { Cause, Exit, Layer, ManagedRuntime, Option } from "effect"
import { useAtomValue, useAtomSet } from "@effect-atom/atom-react"
import { hash } from "starknet"
import { FalconService } from "@/services/FalconService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import {
  keypairAtom,
  packedKeyAtom,
  verificationStepAtom,
  wasmStatusAtom,
  persistKeypair,
  persistPackedKey,
  getExportedFlag,
  setExportedFlag,
} from "@/atoms/falcon"
import { networkAtom } from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import { exportKeyFile, parseKeyFile } from "@/services/keyfile"
import type { PackedPublicKey } from "@/services/types"
import { HexDisplay } from "./HexDisplay"
import { bytesToHex } from "./verification-utils"

const appRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)

function deriveAddress(packedPk: PackedPublicKey, classHash: string): string {
  const constructorCalldata = [...packedPk.slots]
  return hash.calculateContractAddressFromHash("0x1", classHash, constructorCalldata, 0)
}

function truncateAddress(addr: string): string {
  if (addr.length <= 16) return addr
  return addr.slice(0, 10) + "..." + addr.slice(-6)
}

export function KeyManagementPanel(): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const packedKey = useAtomValue(packedKeyAtom)
  const step = useAtomValue(verificationStepAtom)
  const setKeypair = useAtomSet(keypairAtom)
  const setPackedKey = useAtomSet(packedKeyAtom)
  const setStep = useAtomSet(verificationStepAtom)
  const setWasmStatus = useAtomSet(wasmStatusAtom)
  const networkId = useAtomValue(networkAtom)
  const networkConfig = NETWORKS[networkId]

  const [showNtt, setShowNtt] = useState(false)
  const [showPacked, setShowPacked] = useState(false)
  const [hasExported, setHasExported] = useState(getExportedFlag)
  const [confirmReplace, setConfirmReplace] = useState<{
    currentAddr: string
    newAddr: string
    proceed: () => void
  } | null>(null)

  // Sync exported flag from localStorage when keypair changes
  useEffect(() => {
    setHasExported(getExportedFlag())
  }, [keypair])

  const isBusy = step.step === "generating-keypair"

  // Derive address from current packed key for display
  const currentAddress = Option.match(packedKey, {
    onNone: () => null,
    onSome: (pk) => {
      if (networkConfig.classHash === "0x0") return null
      return deriveAddress(pk, networkConfig.classHash)
    },
  })

  const packPublicKey = useCallback(
    async (pkNtt: Int32Array) => {
      const pkNtt16 = new Uint16Array(pkNtt.length)
      for (let i = 0; i < pkNtt.length; i++) pkNtt16[i] = pkNtt[i]
      const exit = await appRuntime.runPromiseExit(
        FalconService.packPublicKey(pkNtt16),
      )
      if (Exit.isSuccess(exit)) {
        setPackedKey(Option.some(exit.value))
        persistPackedKey(Option.some(exit.value))
      }
    },
    [setPackedKey],
  )

  const handleGenerate = useCallback(async () => {
    // Guard: if keypair already exists, confirm before replacing
    if (Option.isSome(keypair) && Option.isSome(packedKey)) {
      const existingAddr = currentAddress
      if (existingAddr) {
        const userConfirmed = window.confirm(
          `You already have a wallet at ${truncateAddress(existingAddr)}.\n\nGenerating a new key will replace it. Make sure you've exported your current key first.\n\nContinue?`
        )
        if (!userConfirmed) return
      }
    }

    setStep({ step: "generating-keypair" })
    setPackedKey(Option.none())
    persistPackedKey(Option.none())
    const seed = crypto.getRandomValues(new Uint8Array(32))

    const exit = await appRuntime.runPromiseExit(
      FalconService.generateKeypair(seed),
    )

    if (Exit.isSuccess(exit)) {
      const kpOption = Option.some(exit.value)
      setKeypair(kpOption)
      persistKeypair(kpOption)
      setExportedFlag(false)
      setHasExported(false)
      setWasmStatus("ready")
      setStep({ step: "idle" })
      await packPublicKey(exit.value.publicKeyNtt)
    } else {
      const errOpt = Cause.failureOption(exit.cause)
      const msg = Option.match(errOpt, {
        onNone: () => "Keypair generation failed",
        onSome: (e) => e.message,
      })
      setStep({ step: "error", message: msg })
    }
  }, [setKeypair, setPackedKey, setStep, setWasmStatus, packPublicKey, keypair, packedKey, currentAddress])

  const applyImport = useCallback(
    async (text: string) => {
      const exit = await appRuntime.runPromiseExit(parseKeyFile(text))

      if (Exit.isSuccess(exit)) {
        const kpOption = Option.some(exit.value.keypair)
        const pkOption = Option.some(exit.value.packedPublicKey)
        setKeypair(kpOption)
        setPackedKey(pkOption)
        persistKeypair(kpOption)
        persistPackedKey(pkOption)
        setExportedFlag(true) // imported from file = effectively backed up
        setHasExported(true)
        setWasmStatus("ready")
        setStep({ step: "idle" })
      } else {
        const errOpt = Cause.failureOption(exit.cause)
        const msg = Option.match(errOpt, {
          onNone: () => "Failed to parse key file",
          onSome: (e) => e.message,
        })
        setStep({ step: "error", message: msg })
      }
    },
    [setKeypair, setPackedKey, setWasmStatus, setStep],
  )

  const handleImport = useCallback(() => {
    const input = document.createElement("input")
    input.type = "file"
    input.accept = ".json"
    input.onchange = async () => {
      const file = input.files?.[0]
      if (!file) return
      const text = await file.text()

      // Parse the imported key to check for address mismatch
      const parseExit = await appRuntime.runPromiseExit(parseKeyFile(text))
      if (Exit.isFailure(parseExit)) {
        applyImport(text) // let applyImport show the error
        return
      }

      const importedPk = parseExit.value.packedPublicKey
      const hasExisting = Option.isSome(packedKey)

      if (hasExisting && networkConfig.classHash !== "0x0") {
        const existingPk = Option.getOrThrow(packedKey)
        const existingAddr = deriveAddress(existingPk, networkConfig.classHash)
        const importedAddr = deriveAddress(importedPk, networkConfig.classHash)

        if (existingAddr !== importedAddr) {
          setConfirmReplace({
            currentAddr: existingAddr,
            newAddr: importedAddr,
            proceed: () => {
              setConfirmReplace(null)
              applyImport(text)
            },
          })
          return
        }
      }

      applyImport(text)
    }
    input.click()
  }, [packedKey, networkConfig.classHash, applyImport])

  const handleExport = useCallback(() => {
    const kp = Option.match(keypair, { onNone: () => null, onSome: (k) => k })
    const pk = Option.match(packedKey, { onNone: () => null, onSome: (p) => p })
    if (!kp || !pk) return

    const json = exportKeyFile(kp, pk)
    const blob = new Blob([json], { type: "application/json" })
    const url = URL.createObjectURL(blob)
    const a = document.createElement("a")
    a.href = url
    a.download = "falcon-keypair.json"
    a.click()
    URL.revokeObjectURL(url)
    setExportedFlag(true)
    setHasExported(true)
  }, [keypair, packedKey])

  const hasKeypair = Option.isSome(keypair)
  const hasPacked = Option.isSome(packedKey)

  const keypairHex = Option.match(keypair, {
    onNone: () => null,
    onSome: (kp) => "0x" + bytesToHex(kp.verifyingKey),
  })

  const nttCoeffs = Option.match(keypair, {
    onNone: () => null,
    onSome: (kp) => Array.from(kp.publicKeyNtt),
  })

  const packedSlots = Option.match(packedKey, {
    onNone: () => null,
    onSome: (pk) => pk.slots,
  })

  return (
    <div className="space-y-5">
      <h3 className="text-base font-semibold tracking-tight text-falcon-text/90">Key Management</h3>

      {/* Backup warning */}
      {hasKeypair && !hasExported && (
        <div className="flex items-start gap-3 rounded-xl border border-amber-500/20 bg-amber-500/5 px-4 py-3">
          <span className="mt-0.5 shrink-0 text-amber-400 text-sm">&#9888;</span>
          <div className="flex-1">
            <p className="text-xs font-medium text-amber-300/90">
              Wallet not backed up
            </p>
            <p className="mt-0.5 text-xs text-amber-300/50">
              Export your key file now to avoid losing access to your funds.
            </p>
          </div>
          <button
            onClick={handleExport}
            className="shrink-0 rounded-lg bg-amber-500/15 px-3 py-1.5 text-xs font-medium text-amber-300/90 transition-colors hover:bg-amber-500/25"
          >
            Export Now
          </button>
        </div>
      )}

      {/* Import mismatch confirmation dialog */}
      {confirmReplace && (
        <div className="rounded-xl border border-red-500/20 bg-red-500/5 p-4 space-y-3">
          <p className="text-xs font-medium text-red-300/90">
            Address mismatch detected
          </p>
          <p className="text-xs text-red-300/60">
            Your current wallet is at <span className="font-mono text-red-300/80">{truncateAddress(confirmReplace.currentAddr)}</span>.
            The imported key maps to a different address: <span className="font-mono text-red-300/80">{truncateAddress(confirmReplace.newAddr)}</span>.
          </p>
          <p className="text-xs text-red-300/60">
            Importing will replace your current wallet. Any funds at the old address will only be accessible if you have a backup.
          </p>
          <div className="flex gap-2">
            <button
              onClick={confirmReplace.proceed}
              className="rounded-lg bg-red-500/15 px-4 py-1.5 text-xs font-medium text-red-300/90 transition-colors hover:bg-red-500/25"
            >
              Replace Wallet
            </button>
            <button
              onClick={() => setConfirmReplace(null)}
              className="glass-btn rounded-lg px-4 py-1.5 text-xs font-medium text-falcon-text/40 transition-colors hover:text-falcon-text/70"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      <div className="flex flex-wrap gap-2">
        <button
          onClick={handleGenerate}
          disabled={isBusy}
          className="rounded-xl bg-gradient-to-b from-falcon-primary to-falcon-primary/80 px-5 py-2.5 text-sm font-semibold text-white shadow-md shadow-falcon-primary/15 transition-all duration-200 hover:scale-[1.02] hover:shadow-lg hover:shadow-falcon-primary/20 disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:scale-100"
        >
          {isBusy ? "Generating..." : "Generate"}
        </button>
        <button
          onClick={handleImport}
          disabled={isBusy}
          className="glass-btn rounded-xl px-5 py-2.5 text-sm font-medium text-falcon-text/60 transition-all duration-200 hover:scale-[1.02] hover:text-falcon-text/80 disabled:cursor-not-allowed disabled:opacity-40"
        >
          Import
        </button>
        <button
          onClick={handleExport}
          disabled={!hasKeypair || !hasPacked}
          className="glass-btn rounded-xl px-5 py-2.5 text-sm font-medium text-falcon-text/60 transition-all duration-200 hover:scale-[1.02] hover:text-falcon-text/80 disabled:cursor-not-allowed disabled:opacity-40"
        >
          Export
        </button>
      </div>

      {keypairHex !== null && (
        <div className="space-y-4">
          <HexDisplay
            label="Verifying Key (896-byte h polynomial)"
            value={keypairHex}
            truncate={{ head: 18, tail: 8 }}
          />

          {/* Address display — always show when key exists */}
          {currentAddress && (
            <div className="glass-card-static rounded-xl p-3">
              <p className="text-[10px] font-medium tracking-widest text-falcon-text/20 uppercase">
                Your Starknet Address
              </p>
              <p className="mt-1 break-all font-mono text-xs text-falcon-accent/70">
                {currentAddress}
              </p>
            </div>
          )}

          {nttCoeffs !== null && (
            <div>
              <button
                onClick={() => setShowNtt(!showNtt)}
                className="flex items-center gap-1.5 text-xs font-medium text-falcon-text/30 transition-colors duration-200 hover:text-falcon-text/60"
              >
                <span className="text-[10px]">{showNtt ? "\u25BC" : "\u25B6"}</span>
                NTT Coefficients ({nttCoeffs.length})
              </button>
              {showNtt && (
                <div className="glass-display mt-2 max-h-32 overflow-y-auto rounded-lg px-3 py-2 font-mono text-xs text-falcon-accent/50">
                  [{nttCoeffs.slice(0, 20).join(", ")}
                  {nttCoeffs.length > 20 && `, ... ${nttCoeffs.length - 20} more`}]
                </div>
              )}
            </div>
          )}

          {packedSlots !== null && (
            <div>
              <button
                onClick={() => setShowPacked(!showPacked)}
                className="flex items-center gap-1.5 text-xs font-medium text-falcon-text/30 transition-colors duration-200 hover:text-falcon-text/60"
              >
                <span className="text-[10px]">{showPacked ? "\u25BC" : "\u25B6"}</span>
                Packed Public Key ({packedSlots.length} felt252 slots)
              </button>
              {showPacked && (
                <HexDisplay
                  label=""
                  value={packedSlots}
                  maxRows={29}
                  truncate={{ head: 18, tail: 8 }}
                />
              )}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

"use client"

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react"
import { useAtomSet, useAtomValue } from "@effect-atom/atom-react"
import { Exit, Layer, ManagedRuntime, Option } from "effect"
import { keypairAtom, packedKeyAtom } from "@/atoms/falcon"
import {
  deployStepAtom,
  deployedAddressAtom,
  deployTxHashAtom,
  networkAtom,
} from "@/atoms/starknet"
import { NETWORKS } from "@/config/networks"
import type { NetworkConfig } from "@/config/networks"
import { FalconService } from "@/services/FalconService"
import { FalconSigner } from "@/services/FalconSigner"
import { StarknetService } from "@/services/StarknetService"
import { WasmRuntimeLive } from "@/services/WasmRuntime"
import type { DevnetAccount } from "@/services/types"
import { SendTransaction } from "./SendTransaction"
import { extractUserMessage } from "@/services/error-messages"
import { AddressDisplay } from "@/components/ui/AddressDisplay"
import { ExplorerLink } from "@/components/ui/ExplorerLink"
import { TokenAmount } from "@/components/ui/TokenAmount"
import { TransactionPending } from "@/components/ui/TransactionPending"
import type { PreparedAccountDeploy } from "./accountDeployPipeline"
import {
  deployAccountEffect,
  prepareAccountDeployEffect,
} from "./accountDeployPipeline"

const falconRuntime = ManagedRuntime.make(
  FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
)

function createDeployRuntime(config: NetworkConfig) {
  return ManagedRuntime.make(
    Layer.mergeAll(
      FalconService.Default.pipe(Layer.provide(WasmRuntimeLive)),
      StarknetService.make(config.rpcUrl, config.classHash),
    ),
  )
}


export function AccountDeployFlow(): React.JSX.Element {
  const keypair = useAtomValue(keypairAtom)
  const packedKey = useAtomValue(packedKeyAtom)
  const deployStep = useAtomValue(deployStepAtom)
  const setKeypair = useAtomSet(keypairAtom)
  const setDeployStep = useAtomSet(deployStepAtom)
  const setDeployedAddress = useAtomSet(deployedAddressAtom)
  const setDeployTxHash = useAtomSet(deployTxHashAtom)
  const networkId = useAtomValue(networkAtom)
  const networkConfig = NETWORKS[networkId]

  const deployRuntimeRef = useRef(createDeployRuntime(networkConfig))
  const prevNetworkRef = useRef(networkId)
  if (prevNetworkRef.current !== networkId) {
    prevNetworkRef.current = networkId
    deployRuntimeRef.current = createDeployRuntime(networkConfig)
  }

  const [privateKey, setPrivateKey] = useState("")
  const [devnetAccounts, setDevnetAccounts] = useState<DevnetAccount[]>([])
  const [preparedDeploy, setPreparedDeploy] =
    useState<Option.Option<PreparedAccountDeploy>>(Option.none())
  const [balance, setBalance] = useState<bigint | null>(null)
  const [autoRestoring, setAutoRestoring] = useState(false)

  // ── Auto-restore: if keypair+packedKey exist in localStorage, restore flow state ──
  const autoRestoreRan = useRef(false)
  useEffect(() => {
    if (autoRestoreRan.current) return
    if (!Option.isSome(keypair) || !Option.isSome(packedKey)) return
    if (deployStep.step !== "idle") return
    if (networkConfig.classHash === "0x0") return

    autoRestoreRan.current = true
    setAutoRestoring(true)

    const restore = async () => {
      // Prepare using existing keypair
      const prepareExit = await deployRuntimeRef.current.runPromiseExit(
        prepareAccountDeployEffect({
          privateKey: "",
          existingKeypair: keypair,
        }),
      )

      if (Exit.isFailure(prepareExit)) {
        setAutoRestoring(false)
        return
      }

      const prepared = prepareExit.value
      setPreparedDeploy(Option.some(prepared))

      // Check if already deployed on-chain
      const deployedExit = await deployRuntimeRef.current.runPromiseExit(
        StarknetService.isDeployed(prepared.address),
      )

      if (Exit.isSuccess(deployedExit) && deployedExit.value) {
        // Already deployed — skip straight to deployed state
        setDeployedAddress(Option.some(prepared.address))
        setDeployTxHash(Option.some("already-deployed" as any))
        setDeployStep({
          step: "deployed",
          txHash: "already-deployed" as any,
          address: prepared.address,
        })
        setAutoRestoring(false)
        return
      }

      // Not deployed — check balance and go to awaiting-funds
      setDeployStep({ step: "awaiting-funds", address: prepared.address })
      setAutoRestoring(false)
    }

    restore()
  }, [keypair, packedKey, deployStep.step, networkConfig.classHash, setDeployStep, setDeployedAddress, setDeployTxHash])

  // Reset on network change
  useEffect(() => {
    setDeployStep({ step: "idle" })
    setPreparedDeploy(Option.none())
    setBalance(null)
    autoRestoreRan.current = false
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [networkId])

  useEffect(() => {
    if (!networkConfig.isDevnet) {
      setDevnetAccounts([])
      return
    }
    let cancelled = false
    const fetchAccounts = async () => {
      const exit = await deployRuntimeRef.current.runPromiseExit(
        StarknetService.fetchPrefundedAccounts(),
      )
      if (!cancelled && Exit.isSuccess(exit)) {
        setDevnetAccounts(exit.value)
        if (exit.value.length > 0) {
          setPrivateKey(exit.value[0].private_key)
        }
      }
    }
    fetchAccounts()
    return () => { cancelled = true }
  }, [networkConfig.isDevnet])

  const hasKeypair = Option.isSome(keypair)

  useEffect(() => {
    if (deployStep.step !== "awaiting-funds") {
      setBalance(null)
      return
    }

    let cancelled = false

    const poll = async () => {
      const exit = await deployRuntimeRef.current.runPromiseExit(
        StarknetService.getBalance(deployStep.address),
      )
      if (!cancelled && Exit.isSuccess(exit)) {
        setBalance(exit.value)
      }
    }

    poll()
    const interval = setInterval(poll, 5000)
    return () => {
      cancelled = true
      clearInterval(interval)
    }
  }, [deployStep])

  const handlePrepare = useCallback(async () => {
    setDeployStep({ step: hasKeypair ? "packing" : "generating-keypair" })
    setDeployTxHash(Option.none())
    setDeployedAddress(Option.none())
    setPreparedDeploy(Option.none())

    const prepareExit = await deployRuntimeRef.current.runPromiseExit(
      prepareAccountDeployEffect({
        privateKey,
        existingKeypair: keypair,
      }),
    )

    if (Exit.isFailure(prepareExit)) {
      setDeployStep({
        step: "error",
        message: extractUserMessage(prepareExit, "Failed to prepare deployment"),
      })
      return
    }

    const prepared = prepareExit.value
    setPreparedDeploy(Option.some(prepared))
    setKeypair(Option.some(prepared.keypair))
    setDeployStep({ step: "awaiting-funds", address: prepared.address })
  }, [
    hasKeypair,
    keypair,
    privateKey,
    setDeployStep,
    setDeployTxHash,
    setDeployedAddress,
    setKeypair,
  ])

  const handleDeploy = useCallback(async () => {
    const prepared = Option.match(preparedDeploy, {
      onNone: () => null,
      onSome: (value) => value,
    })
    if (prepared === null) {
      setDeployStep({
        step: "error",
        message: "Prepare the deployment before submitting.",
      })
      return
    }

    setDeployStep({ step: "deploying", address: prepared.address })
    const signer = new FalconSigner(
      prepared.keypair.secretKey,
      prepared.keypair.publicKeyNtt,
      falconRuntime,
    )
    const deployExit = await deployRuntimeRef.current.runPromiseExit(
      deployAccountEffect({
        address: prepared.address,
        packedPublicKey: prepared.packedPublicKey,
        signer,
        salt: prepared.salt,
        requiredBalance: 1n,
      }),
    )

    if (Exit.isFailure(deployExit)) {
      setDeployStep({
        step: "error",
        message: extractUserMessage(deployExit, "Account deployment failed"),
      })
      return
    }

    setDeployTxHash(Option.some(deployExit.value.txHash))
    setDeployedAddress(Option.some(deployExit.value.address))
    setDeployStep({
      step: "deployed",
      txHash: deployExit.value.txHash,
      address: deployExit.value.address,
    })
  }, [preparedDeploy, setDeployStep, setDeployTxHash, setDeployedAddress])

  const handleReset = useCallback(() => {
    setPreparedDeploy(Option.none())
    setDeployTxHash(Option.none())
    setDeployedAddress(Option.none())
    setDeployStep({ step: "idle" })
    autoRestoreRan.current = false
  }, [setDeployStep, setDeployTxHash, setDeployedAddress])

  const stepFlags = useMemo(() => {
    const stepName = deployStep.step

    const step1Complete =
      hasKeypair ||
      stepName === "packing" ||
      stepName === "computing-address" ||
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step2Complete =
      stepName === "computing-address" ||
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step3Complete =
      stepName === "awaiting-funds" ||
      stepName === "deploying" ||
      stepName === "deployed"

    const step4Complete = stepName === "deploying" || stepName === "deployed"
    const step5Complete = stepName === "deployed"

    return {
      step1Active: stepName === "generating-keypair",
      step2Active: stepName === "packing",
      step3Active: stepName === "computing-address",
      step4Active: stepName === "awaiting-funds",
      step5Active: stepName === "deploying",
      step1Complete,
      step2Complete,
      step3Complete,
      step4Complete,
      step5Complete,
    }
  }, [deployStep.step, hasKeypair])

  const liveStatus = useMemo(() => {
    switch (deployStep.step) {
      case "idle":
        return "Account deploy flow is idle."
      case "generating-keypair":
        return "Generating Falcon keypair."
      case "packing":
        return "Packing Falcon public key."
      case "computing-address":
        return "Computing Starknet deploy address."
      case "awaiting-funds":
        return `Waiting for funds at ${deployStep.address}.`
      case "deploying":
        return "Deploying account transaction."
      case "deployed":
        return `Account deployed with transaction hash ${deployStep.txHash}.`
      case "error":
        return deployStep.message
    }
  }, [deployStep])

  const isAlreadyDeployed = deployStep.step === "deployed" && deployStep.txHash === "already-deployed"

  const DEPLOY_STEPS = [
    { number: 1, title: "Generate Keypair", description: "Create or reuse a Falcon-512 keypair.", active: stepFlags.step1Active, complete: stepFlags.step1Complete },
    { number: 2, title: "Pack Public Key", description: "Compress public key into 29 felt252 slots.", active: stepFlags.step2Active, complete: stepFlags.step2Complete },
    { number: 3, title: "Compute Address", description: "Compute the counterfactual address.", active: stepFlags.step3Active, complete: stepFlags.step3Complete },
    { number: 4, title: "Fund Account", description: "Send STRK to the pre-computed address.", active: stepFlags.step4Active, complete: stepFlags.step4Complete },
