284→  to { opacity: 1; transform: translateY(0); }
285→}
286→
287→.animate-fade-in {
288→  animation: fade-in 0.3s cubic-bezier(0.32, 0.72, 0, 1) both;
289→}
290→
291→.animate-scale-in {
292→  animation: scale-in 0.2s cubic-bezier(0.32, 0.72, 0, 1) both;
293→}
294→
295→.animate-slide-up {
296→  animation: slide-up 0.4s cubic-bezier(0.32, 0.72, 0, 1) both;
297→}
298→
299→.animate-pulse-glow {
300→  animation: pulse-glow 2s ease-in-out infinite;
301→}
302→
303→.stagger-delay-1 { animation-delay: 50ms; }
304→.stagger-delay-2 { animation-delay: 100ms; }
305→.stagger-delay-3 { animation-delay: 150ms; }
306→.stagger-delay-4 { animation-delay: 200ms; }
307→.stagger-delay-5 { animation-delay: 250ms; }
308→
309→/* ─── Transaction pending animations ──────────────────────────────── */
310→@keyframes spin-ring {
311→  to { transform: rotate(360deg); }
312→}
313→
314→@keyframes progress-indeterminate {
315→  0% { transform: translateX(-100%); }
316→  50% { transform: translateX(0%); }
317→  100% { transform: translateX(200%); }
318→}
319→
320→@keyframes text-breathe {
321→  0%, 100% { opacity: 0.8; }
322→  50% { opacity: 0.4; }
323→}
324→
325→.animate-spin-ring {
326→  animation: spin-ring 1.2s cubic-bezier(0.5, 0, 0.5, 1) infinite;
327→}
328→
329→.animate-progress-indeterminate {
330→  animation: progress-indeterminate 2s cubic-bezier(0.4, 0, 0.2, 1) infinite;
331→}
332→
333→.animate-text-breathe {
334→  animation: text-breathe 2.4s ease-in-out infinite;
335→}
336→
337→@media (prefers-reduced-motion: reduce) {
338→  .animate-fade-in,
339→  .animate-scale-in,
340→  .animate-slide-up,
341→  .animate-pulse-glow,
342→  .animate-spin-ring,
343→  .animate-progress-indeterminate,
344→  .animate-text-breathe {
345→    animation: none;
346→  }
347→}
348→
349→/* ─── Custom scrollbar ─────────────────────────────────────────────── */
350→::-webkit-scrollbar {
351→  width: 6px;
352→  height: 6px;
353→}
354→
355→::-webkit-scrollbar-track {
356→  background: transparent;
357→}
358→
359→::-webkit-scrollbar-thumb {
360→  background: var(--glass-border-hover);
361→  border-radius: 3px;
362→}
363→
364→::-webkit-scrollbar-thumb:hover {
365→  background: rgba(255, 255, 255, 0.15);
366→}
367→
368→.light ::-webkit-scrollbar-thumb:hover {
369→  background: rgba(0, 0, 0, 0.15);
370→}
371→
372→/* ─── Lattice grid animation (hero background) ────────────────────── */
373→@keyframes lattice-drift {
374→  0% { transform: translate(0, 0); }
375→  50% { transform: translate(-8px, 6px); }
376→  100% { transform: translate(0, 0); }
377→}
378→
379→.lattice-grid {
380→  position: absolute;
381→  inset: 0;
382→  overflow: hidden;
383→  pointer-events: none;
384→  opacity: 0.15;
385→}
386→
387→.lattice-grid::before {
388→  content: "";
389→  position: absolute;
390→  inset: -20px;
391→  background-image:
392→    radial-gradient(circle, var(--color-falcon-accent) 1px, transparent 1px),
393→    radial-gradient(circle, var(--color-falcon-primary) 0.5px, transparent 0.5px);
394→  background-size: 60px 60px, 60px 60px;
395→  background-position: 0 0, 30px 30px;
396→  animation: lattice-drift 20s ease-in-out infinite;
397→}
398→
399→.lattice-grid::after {
400→  content: "";
401→  position: absolute;
402→  inset: 0;
403→  background: radial-gradient(ellipse at center, transparent 30%, var(--color-falcon-bg) 70%);
404→}
405→
406→@media (prefers-reduced-motion: reduce) {
407→  .lattice-grid::before {
408→    animation: none;
409→  }
410→}
411→
412→/* ─── Comparison bar chart ─────────────────────────────────────────── */
413→.comparison-bar {
414→  height: 2.5rem;
415→  border-radius: 0.75rem;
416→  transition: width 1.2s cubic-bezier(0.32, 0.72, 0, 1);
417→}
418→
419→.comparison-bar[data-visible="false"] {
420→  width: 0 !important;
421→}
422→
423→/* ─── Starknet pitch section ──────────────────────────────────────── */
424→.starknet-section {
425→  background:
426→    radial-gradient(ellipse at 50% 0%, rgba(99, 102, 241, 0.08) 0%, transparent 60%),
427→    var(--glass-bg);
428→  border-top: 1px solid rgba(99, 102, 241, 0.1);
429→  border-bottom: 1px solid rgba(99, 102, 241, 0.1);
430→}
431→
432→.light .starknet-section {
433→  background:
434→    radial-gradient(ellipse at 50% 0%, rgba(99, 102, 241, 0.06) 0%, transparent 60%),
435→    var(--glass-bg);
436→}
